const contact = $('Find Notion Contact').first().json;
const props = contact.properties;
const contactName = props['Name']?.title?.[0]?.text?.content || 'Unknown';
const companyName = props['Company']?.rich_text?.[0]?.text?.content || 'Unknown-Company';
const existingFolderId = props['Drive Folder ID']?.rich_text?.[0]?.text?.content || '';
// Use the GitHub repo name from the form (set during STEP4)
const repoName = $('Extract Form Data').item.json.github_repo_name;
return [{ json: {
  notion_page_id: contact.id,
  contact_name: contactName,
  company_name: companyName,
  contact_email: props['Email']?.email || '',
  existing_folder_id: existingFolderId,
  github_repo_name: repoName
}}];

