const raw = $json.content?.[0]?.text || $json.message?.content?.[0]?.text || $json.text || '';

function getSection(text, marker) {
  const start = text.indexOf(marker);
  if (start === -1) return '';
  const afterMarker = text.substring(start + marker.length);
  const nextMarker = afterMarker.search(/===\w+===/);
  return nextMarker === -1 ? afterMarker.trim() : afterMarker.substring(0, nextMarker).trim();
}

const meetingNotes = getSection(raw, '===MEETING_NOTES===');
const proposal = getSection(raw, '===PROPOSAL===');
const implementationGuide = getSection(raw, '===IMPLEMENTATION_GUIDE===');
const actionItemsRaw = getSection(raw, '===ACTION_ITEMS===');

let actionItems = [];
try {
  const jsonMatch = actionItemsRaw.match(/\[.*\]/s);
  if (jsonMatch) actionItems = JSON.parse(jsonMatch[0]);
} catch(e) { /* fallback to empty */ }

return [{ json: {
  meeting_notes: meetingNotes,
  proposal: proposal,
  implementation_guide: implementationGuide,
  action_items: actionItems,
  action_items_text: actionItems.map(a => `[${a.priority}] ${a.owner}: ${a.task}`).join('\n'),
  full_response: raw
}}];

